    if (n == 1) {
        return new ArrayList<Integer>();
    }
    int max = (int)(Math.sqrt(n) + 1.0);
    ArrayList<Integer> list = new ArrayList<Integer>();
    for (int i=2; i < max; i++) {
        if (n % i == 0) {
            list.addAll(get_factors(n / i));
            list.add(i);
            break;
        }
    }
    return list;
}
